#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n, x; scanf("%d %d", &n, &x);
        int dp[1001] = {0};
        dp[0] = 1;
        for(int i=0;i<n;i++){
            int a; scanf("%d", &a);
            for(int s=x; s>=a; --s){
                if(dp[s-a]) dp[s] = 1;
            }
        }
        printf(dp[x] ? "YES\n" : "NO\n");
    }
    return 0;
}

